{"content": "import http from 'http'
import fs from 'fs'
import path from 'path'

const BASE = 'http://localhost:3080'

function fetch(path) {
  return new Promise((resolve, reject) => {
    http.get(BASE + path, res => {
      let data = ''
      res.on('data', c => data += c)
      res.on('end', () => {
        try { resolve(JSON.parse(data)) } catch { reject(new Error(data)) }
      })
    }).on('error', reject)
  })
}

/**
 * Get price for a specific strike and type
 */
function getOptionPrice(chain, strike, type, useMid = true) {
  const option = chain.find(r => r.strike === strike && r.type === type)
  if (!option) return null
  if (useMid) return (option.bid + option.ask) / 2
  return { bid: option.bid, ask: option.ask, mid: (option.bid + option.ask) / 2 }
}

/**
 * Calculate the credit of an Iron Condor (in points)
 * CORRECT STRUCTURE:
 * - Sell Call @ strike
 * - Buy Call @ strike + 15
 * - Sell Put @ strike (SAME as call)
 * - Buy Put @ strike - 15
 */
function getIronCondorCredit(chain, spot) {
  const strikeX = Math.round(spot / 5) * 5

  const shortCallStrike = strikeX
  const longCallStrike = strikeX + 15
  const shortPutStrike = strikeX
  const longPutStrike = strikeX - 15

  const shortCall = getOptionPrice(chain, shortCallStrike, 'call')
  const longCall = getOptionPrice(chain, longCallStrike, 'call')
  const shortPut = getOptionPrice(chain, shortPutStrike, 'put')
  const longPut = getOptionPrice(chain, longPutStrike, 'put')

  if (!shortCall || !longCall || !shortPut || !longPut) return null

  const credit = (shortCall + shortPut) - (longCall + longPut)

  return {
    creditPoints: Math.round(credit * 100) / 100,
    creditDollars: Math.round(credit * 100 * 100) / 100,
    shortCallStrike,
    longCallStrike,
    shortPutStrike,
    longPutStrike,
  }
}

/**
 * Calculate current mark of an Iron Condor position (in points)
 */
function getIronCondorMark(chain, shortCallStrike, longCallStrike, shortPutStrike, longPutStrike) {
  const shortCall = getOptionPrice(chain, shortCallStrike, 'call')
  const longCall = getOptionPrice(chain, longCallStrike, 'call')
  const shortPut = getOptionPrice(chain, shortPutStrike, 'put')
  const longPut = getOptionPrice(chain, longPutStrike, 'put')

  if (!shortCall || !longCall || !shortPut || !longPut) return null

  const cost = (shortCall + shortPut) - (longCall + longPut)
  return Math.round(cost * 100) / 100
}

/**
 * Get individual leg prices
 */
function getLegPrices(chain, shortCallStrike, longCallStrike, shortPutStrike, longPutStrike) {
  return {
    shortCallPrice: getOptionPrice(chain, shortCallStrike, 'call'),
    longCallPrice: getOptionPrice(chain, longCallStrike, 'call'),
    shortPutPrice: getOptionPrice(chain, shortPutStrike, 'put'),
    longPutPrice: getOptionPrice(chain, longPutStrike, 'put'),
  }
}

