import fs from 'fs'
import path from 'path'

const BASE = 'http://localhost:3080'

function fetch(path) {
  return new Promise((resolve, reject) => {
    http.get(BASE + path, res => {
      let data = ''
      res.on('data', c => data += c)
      res.on('end', () => {
        try { resolve(JSON.parse(data)) } catch { reject(new Error(data)) }
      })
    }).on('error', reject)
  })
}

/**
 * Get ASK price for opening a position
 */
function getOpeningPrice(chain, strike, type) {
  const option = chain.find(r => r.strike === strike && r.type === type)
  if (!option) return null
  return option.ask  // We PAY the ask to open
}

/**
 * Get BID price for closing a position
 */
function getClosingPrice(chain, strike, type) {
  const option = chain.find(r => r.strike === strike && r.type === type)
  if (!option) return null
  return option.bid  // We GET the bid to close
}

/**
 * Calculate the credit of an Iron Condor at entry using ASK prices
 * CORRECT STRUCTURE:
 * - Sell Call @ strike (we receive ASK)
 * - Buy Call @ strike + 15 (we pay ASK)
 * - Sell Put @ strike (we receive ASK)
 * - Buy Put @ strike - 15 (we pay ASK)
 */
function getIronCondorCreditAtEntry(chain, spot) {
  const strikeX = Math.round(spot / 5) * 5

  const shortCallStrike = strikeX
  const longCallStrike = strikeX + 15
  const shortPutStrike = strikeX
  const longPutStrike = strikeX - 15

  const shortCallAsk = getOpeningPrice(chain, shortCallStrike, 'call')
  const longCallAsk = getOpeningPrice(chain, longCallStrike, 'call')
  const shortPutAsk = getOpeningPrice(chain, shortPutStrike, 'put')
  const longPutAsk = getOpeningPrice(chain, longPutStrike, 'put')

  if (!shortCallAsk || !longCallAsk || !shortPutAsk || !longPutAsk) return null

  // Credit = what we receive (short) minus what we pay (long)
  const credit = (shortCallAsk + shortPutAsk) - (longCallAsk + longPutAsk)

  return {
    creditPoints: Math.round(credit * 100) / 100,
    creditDollars: Math.round(credit * 100 * 100) / 100,
    shortCallStrike,
    longCallStrike,
    shortPutStrike,
    longPutStrike,
    shortCallPrice: shortCallAsk,
    longCallPrice: longCallAsk,
    shortPutPrice: shortPutAsk,
    longPutPrice: longPutAsk,
  }
}

/**
 * Calculate current mark of an Iron Condor position using BID prices
 * This is what we'd have to pay to close the position
 */
function getIronCondorMarkAtClose(chain, shortCallStrike, longCallStrike, shortPutStrike, longPutStrike) {
  const shortCallBid = getClosingPrice(chain, shortCallStrike, 'call')
  const longCallBid = getClosingPrice(chain, longCallStrike, 'call')
  const shortPutBid = getClosingPrice(chain, shortPutStrike, 'put')
  const longPutBid = getClosingPrice(chain, longPutStrike, 'put')

  if (!shortCallBid || !longCallBid || !shortPutBid || !longPutBid) return null

  // Cost to buyback = what we pay (to close shorts) minus what we receive (close longs)
  const cost = (shortCallBid + shortPutBid) - (longCallBid + longPutBid)
  return Math.round(cost * 100) / 100
}

