/**
 * Main backtest function with minute-by-minute position tracking
 */
async function run() {
  try {
    const sessions = await fetch('/api/sessions')
    const dates = sessions.sessions.filter(s => s.hasSnapshots).map(s => s.date)

    if (dates.length === 0) {
      console.log('No sessions with snapshots available')
      return
    }

    console.log(`Running Iron Condor ATM strategy on ${dates.length} dates...\n`)

    const params = {
      wingWidth: 15,
      scalingDistance: 15,
      tradeEndTime: '15:45',
    }

    let totalTrades = 0
    let profitableTrades = 0
    let totalPnl = 0
    let totalWinPnl = 0
    let totalLossPnl = 0
    let peak = 0
    let maxDD = 0

    const dailyData = []
    const cumulativePnlPoints = []
    let runningPnl = 0

    const timeToMinutes = t => {
      const [h, m] = t.split(':').map(Number)
      return h * 60 + m
    }

    const tradeEndMin = timeToMinutes(params.tradeEndTime)
    const MARKET_OPEN_MINUTE = 9 * 60 + 30

    for (let dayIdx = 0; dayIdx < dates.length; dayIdx++) {
      const date = dates[dayIdx]
      const [session, snapsRes] = await Promise.all([
        fetch(`/api/sessions/${date}`),
        fetch(`/api/sessions/${date}/snapshots`).catch(() => ({ snapshots: [] }))
      ])

      const snapshots = snapsRes.snapshots || []
      if (snapshots.length === 0) continue

      let dayTrades = 0
      let dayWins = 0
      let dayLosses = 0
      let dayPnl = 0
      let dayWinPnl = 0
      let dayLossPnl = 0

      const dayTradeDetails = []
      const positions = []
      let lastEntryStrike = null  // Track the LAST entry strike for strict 15pt stepping
      let tradeCounter = 0
      let marketOpenedThisDay = false

      for (let i = 0; i < snapshots.length; i++) {
        const snap = snapshots[i]
        const [h, m] = snap.time.split(':').map(Number)
        const curMin = h * 60 + m
        const spot = snap.spot
        const chain = snap.chain

        // Update marks for all open positions and check for closures
        for (let pi = positions.length - 1; pi >= 0; pi--) {
          const pos = positions[pi]
          const mark = getIronCondorMarkAtClose(chain, pos.shortCall, pos.longCall, pos.shortPut, pos.longPut)

          if (mark === null) continue

          pos.currentMark = mark
          pos.unrealizedPnl = pos.credit - mark
          pos.lastUpdateTime = snap.time

          // Check if position should be closed (mark <= 10% of credit or 90% of profit taken)
          const closeThreshold = Math.max(0.05, pos.credit * 0.1)
          if (mark <= closeThreshold || pos.unrealizedPnl >= pos.credit * 0.9) {
            const closurePnl = pos.credit - mark
            if (!pos.closures) pos.closures = []
            pos.closures.push({
              time: snap.time,
              spot: spot,
              description: mark <= closeThreshold ? 'Mark reached close threshold' : 'Profit target hit (90% of credit)',
              pnl: closurePnl,
              mark: mark,
            })

            // Finalize trade
            pos.closedAtTime = snap.time
            pos.closedAtSpot = spot
            pos.closedMark = mark
            pos.finalPnl = closurePnl

            dayTradeDetails.push({
              tradeNum: tradeCounter + 1,
              enteredAtTime: pos.enteredAtTime,
              enteredAtSpot: pos.enteredAtSpot,
              strikeX: pos.strikeX,
              shortCall: pos.shortCall,
              longCall: pos.longCall,
              shortCallPrice: pos.shortCallPrice,
              longCallPrice: pos.longCallPrice,
              shortPut: pos.shortPut,
              longPut: pos.longPut,
              shortPutPrice: pos.shortPutPrice,
              longPutPrice: pos.longPutPrice,
              credit: pos.credit,
              closedAtTime: pos.closedAtTime,
              closedAtSpot: pos.closedAtSpot,
              closedMark: mark,
              finalPnl: closurePnl,
              lastUpdateTime: snap.time,
              closures: pos.closures || []
            })

            dayPnl += closurePnl
            dayTrades++
            tradeCounter++
            if (closurePnl > 0) {
              dayWins++
              dayWinPnl += closurePnl
            } else {
              dayLosses++
              dayLossPnl += closurePnl
            }

            positions.splice(pi, 1)
          }
        }

        // Start selling Iron Condors within first 5 minutes of market open
        const withinFirstFiveMinutes = !marketOpenedThisDay && curMin >= MARKET_OPEN_MINUTE && curMin <= MARKET_OPEN_MINUTE + 5
        const afterMarketOpen = marketOpenedThisDay && curMin <= tradeEndMin

        if (withinFirstFiveMinutes || afterMarketOpen) {
          marketOpenedThisDay = true

          // STRICT 15-POINT STEPPING: Check if we should scale based on LAST entry strike
          let shouldScale = false
          if (lastEntryStrike === null) {
            // First trade
            shouldScale = true
          } else {
            // Subsequent trades: must be exactly 15 points away
            const strikeX = Math.round(spot / 5) * 5
            if (Math.abs(strikeX - lastEntryStrike) >= params.scalingDistance) {
              shouldScale = true
            }
          }

          if (shouldScale) {
            const ic = getIronCondorCreditAtEntry(chain, spot)
            if (ic && ic.creditPoints > 0) {
              positions.push({
                tradeNum: tradeCounter + 1,
                enteredAtTime: snap.time,
                enteredAtSpot: spot,
                strikeX: ic.shortCallStrike,
                credit: ic.creditPoints,
                shortCall: ic.shortCallStrike,
                longCall: ic.longCallStrike,
                shortCallPrice: ic.shortCallPrice,
                longCallPrice: ic.longCallPrice,
                shortPut: ic.shortPutStrike,
                longPut: ic.longPutStrike,
                shortPutPrice: ic.shortPutPrice,
                longPutPrice: ic.longPutPrice,
                currentMark: ic.creditPoints,
                unrealizedPnl: 0,
                lastUpdateTime: snap.time,
                closures: []
              })

              lastEntryStrike = ic.shortCallStrike
              console.log(`  [${snap.time}] Trade #${tradeCounter + 1} OPENED @ Strike ${ic.shortCallStrike}, Spot ${spot.toFixed(2)}, Credit \$${(ic.creditPoints * 100).toFixed(0)} (ASK prices)`)
            }
          }
        } else if (curMin > tradeEndMin && positions.length > 0) {
          // Force close all remaining positions at market close
          for (let pi = positions.length - 1; pi >= 0; pi--) {
            const pos = positions[pi]
            const mark = getIronCondorMarkAtClose(chain, pos.shortCall, pos.longCall, pos.shortPut, pos.longPut)
            if (mark !== null) {
              const closurePnl = pos.credit - mark
              if (!pos.closures) pos.closures = []
              pos.closures.push({
                time: snap.time,
                spot: spot,
                description: 'Market close - position force closed (BID prices)',
                pnl: closurePnl,
                mark: mark,
              })

              dayTradeDetails.push({
                tradeNum: tradeCounter + 1,
                enteredAtTime: pos.enteredAtTime,
                enteredAtSpot: pos.enteredAtSpot,
                strikeX: pos.strikeX,
                shortCall: pos.shortCall,
                longCall: pos.longCall,
                shortCallPrice: pos.shortCallPrice,
                longCallPrice: pos.longCallPrice,
                shortPut: pos.shortPut,
                longPut: pos.longPut,
                shortPutPrice: pos.shortPutPrice,
                longPutPrice: pos.longPutPrice,
                credit: pos.credit,
                closedAtTime: snap.time,
                closedAtSpot: spot,
                closedMark: mark,
                finalPnl: closurePnl,
                lastUpdateTime: snap.time,
                closures: pos.closures || []
              })

              dayPnl += closurePnl
              dayTrades++
              tradeCounter++
              if (closurePnl > 0) {
                dayWins++
                dayWinPnl += closurePnl
              } else {
                dayLosses++
                dayLossPnl += closurePnl
              }
            }
            positions.splice(pi, 1)
          }
        }
      }

      // Close any remaining positions at end of data
      if (positions.length > 0) {
        const lastSnap = snapshots[snapshots.length - 1]
        for (const pos of positions) {
          const mark = getIronCondorMarkAtClose(lastSnap.chain, pos.shortCall, pos.longCall, pos.shortPut, pos.longPut)
          if (mark !== null) {
            const closurePnl = pos.credit - mark
            if (!pos.closures) pos.closures = []
            pos.closures.push({
              time: lastSnap.time,
              spot: lastSnap.spot,
              description: 'End of day - position closed at last data point (BID prices)',
              pnl: closurePnl,
              mark: mark,
            })

            dayTradeDetails.push({
              tradeNum: tradeCounter + 1,
              enteredAtTime: pos.enteredAtTime,
              enteredAtSpot: pos.enteredAtSpot,
              strikeX: pos.strikeX,
              shortCall: pos.shortCall,
              longCall: pos.longCall,
              shortCallPrice: pos.shortCallPrice,
              longCallPrice: pos.longCallPrice,
              shortPut: pos.shortPut,
              longPut: pos.longPut,
              shortPutPrice: pos.shortPutPrice,
              longPutPrice: pos.longPutPrice,
              credit: pos.credit,
              closedAtTime: lastSnap.time,
              closedAtSpot: lastSnap.spot,
              closedMark: mark,
              finalPnl: closurePnl,
              lastUpdateTime: lastSnap.time,
              closures: pos.closures || []
            })

            dayPnl += closurePnl
            dayTrades++
            tradeCounter++
            if (closurePnl > 0) {
              dayWins++
              dayWinPnl += closurePnl
            } else {
              dayLosses++
              dayLossPnl += closurePnl
            }
          }
        }
      }

      if (dayTrades > 0) {
        runningPnl += dayPnl
        cumulativePnlPoints.push({ date, pnl: runningPnl })

        dailyData.push({
          date,
          dayNumber: dayIdx + 1,
          tradesCount: dayTrades,
          wins: dayWins,
          losses: dayLosses,
          winRate: (dayWins / dayTrades) * 100,
          dailyPnl: dayPnl,
          avgTrade: dayPnl / dayTrades,
          cumulativePnl: runningPnl,
          trades: dayTradeDetails,
        })

        console.log(`${date}: ${dayTrades} trades opened, ${dayWins}W/${dayLosses}L, Daily P&L: $${(dayPnl * 100).toFixed(0)}, Cumulative: $${(runningPnl * 100).toFixed(0)}\n`)
      }

      totalTrades += dayTrades
      profitableTrades += dayWins
      totalPnl += dayPnl
      totalWinPnl += dayWinPnl
      totalLossPnl += dayLossPnl

      if (runningPnl > peak) peak = runningPnl
      const dd = peak > 0 ? ((peak - runningPnl) / peak) * 100 : 0
      if (dd > maxDD) maxDD = dd
    }

    const winRate = totalTrades > 0 ? (profitableTrades / totalTrades) * 100 : 0
    const avgPerTrade = totalTrades > 0 ? totalPnl / totalTrades : 0
    const profitFactor = totalLossPnl !== 0 ? Math.abs(totalWinPnl / totalLossPnl) : 0

    const summary = {
      totalTrades,
      winRate,
      totalPnl,
      avgPerTrade,
      profitFactor,
      maxDrawdown: maxDD,
    }

    const cumulativePnlChart = {
      labels: cumulativePnlPoints.map(p => p.date),
      data: cumulativePnlPoints.map(p => p.pnl),
    }

    const dailyPnlChart = {
      labels: dailyData.map(d => d.date),
      data: dailyData.map(d => d.dailyPnl),
      colors: dailyData.map(d => d.dailyPnl >= 0 ? 'rgba(34, 197, 94, 0.8)' : 'rgba(239, 68, 68, 0.8)'),
    }

    const htmlData = {
      summary,
      dailyData,
      cumulativePnlChart,
      dailyPnlChart,
    }

    const html = generateHTMLReport(htmlData)
    const outputPath = path.resolve('iron-condor-backtest-results.html')
    fs.writeFileSync(outputPath, html)

    console.log(`${'='.repeat(80)}`)
    console.log(`IRON CONDOR ATM STRATEGY RESULTS`)
    console.log(`Pricing: ASK to open | BID to close | Strict 15-point stepping`)
    console.log(`${'='.repeat(80)}`)
    console.log(`Total Trades Opened: ${totalTrades}`)
    console.log(`Profitable Trades: ${profitableTrades}`)
    console.log(`Win Rate: ${winRate.toFixed(1)}%`)
    console.log(`Total P&L: $${(totalPnl * 100).toFixed(0)}`)
    console.log(`Average Per Trade: $${(avgPerTrade * 100).toFixed(0)}`)
    console.log(`Profit Factor: ${profitFactor.toFixed(2)}x`)
    console.log(`Max Drawdown: ${maxDD.toFixed(2)}%`)
    console.log(`${'='.repeat(80)}`)
    console.log(`\n✅ Detailed report saved to: ${outputPath}`)
    console.log(`📊 Open the HTML file in your browser to see all trades with ASK/BID pricing breakdown`)

  } catch (err) {
    console.error('Error:', err.message)
  }
}

run().catch(console.error)
